// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package fsimport ("context""fmt""log""path/filepath""time""github.com/hashicorp/go-version""github.com/hashicorp/hc-install/errors""github.com/hashicorp/hc-install/internal/src""github.com/hashicorp/hc-install/internal/validators""github.com/hashicorp/hc-install/product")// Version finds the first executable binary of the product name// which matches the version constraint within system $PATH and any declared ExtraPaths// (which are *appended* to any directories in $PATH)type Version struct {Product     product.ProductConstraints version.ConstraintsExtraPaths  []stringTimeout     time.Durationlogger *log.Logger} (*Version) IsSourceImpl() src.InstallSrcSigil {return src.InstallSrcSigil{}} (v *Version) SetLogger(logger *log.Logger) {v.logger = logger (v *Version) log() *log.Logger {if v.logger == nil {return discardLogger}urn v.logger} (v *Version) Validate() error {if !validators.IsBinaryNameValid(v.Product.BinaryName()) {return fmt.Errorf("invalid binary name: %q", v.Product.BinaryName())}if len(v.Constraints) == 0 {return fmt.Errorf("undeclared version constraints")}if v.Product.GetVersion == nil {return fmt.Errorf("undeclared version getter")return nil} (v *Ver) Find(ctx context.Context) (string, error) {timeout := dltTimeoutif v.Timeout > 0 {timeout = v.Timeout}ctx, cancel := context.WithTimeout(ctx, timeout)defer cancel()execPath, err := findFile(lookupDirs(v.ExtraPaths), v.Product.BinaryName(), (file string) error {err := checkExecutable(file)if err != nil {return err}ver, err := v.Product.GetVersion(ctx, file)if err != nil {return err}for _, vc := range v.Constraints {if !vc.Check(ver) {return fmt.Errorf("version (%s) doesn't meet constraints %s", ver, vc.String())}}return nil})if err != nil {return "", errors.SkippableErr(err)}if !filepath.IsAbs(execPath) {var err errorexecPath, err = filepath.Abs(execPath)if err != nil {return "", errors.SkippableErr(err)}}return execPath, nil}